python3 -c "
import csv
from datetime import datetime

with open('market.csv', 'r') as f:
    reader = csv.DictReader(f)
    rows = list(reader)

active = [r for r in rows if r['is_resolved'] == 'False']
resolved = [r for r in rows if r['is_resolved'] == 'True']

print(f'Total: {len(rows)}, Resolved: {len(resolved)}, Active: {len(active)}')
print()

def parse_date(d):
    try:
        return datetime.strptime(d, '%Y-%m-%d')
    except:
        return datetime(2099, 1, 1)

active_sorted = sorted(active, key=lambda r: parse_date(r['resolution_date']))

# Show next questions resolving
print('=== Next questions to resolve ===')
count = 0
for r in active_sorted:
    rd = r['resolution_date']
    if rd and rd.startswith('2026-02-2'):
        count += 1
        if count <= 20:
            pred = r.get('my_prediction', '')
            has_pred = 'Yes' if pred and pred != '' and pred != 'None' else 'No'
            print(f\"{r['qid']} | {rd} | pred={has_pred} | {r['title'][:80]}\")
    elif rd and rd.startswith('2026-03'):
        if count < 5:
            count += 1
            print(f\"{r['qid']} | {rd} | {r['title'][:80]}\")
"

